import type { FunctionComponent, ReactElement, Context } from 'react';
import type { I18n, Locale } from '@meli/i18n';

type DeviceType = 'desktop' | 'mobile' | 'tablet';

type DeviceContext = 'android' | 'ios' | 'smartpos' | 'web';

export type Device = {
  mobile?: boolean;
  nativeApp?: {
    os: DeviceContext;
  };
  osName?: DeviceContext;
  type?: DeviceType;
  webView?: boolean;
};

type AndesProviderSpecificProps = {
  children: ReactElement;

  /**
   * Application locale.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/context#andesprovider-api | Documentation}
   */
  locale: Locale;

  /**
   * Object with device information.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/context#andesprovider-api | Documentation}
   */
  device?: Device;

  /**
   * CSRF protection token.
   *
   * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/context#andesprovider-api | Documentation}
   */
  csrfToken?: string;
};

/**
 * Shared utilities to consume/provide internal and external application context.
 *
 * @see {@link https://github.com/melisource/fury_frontend-andes-ui/tree/master/packages/context | Documentation}
 * @example
 * // app/pages/my-page/controller.js
 * import { AndesProvider } from '@andes/context';
 * import View from './view';
 *
 * export function render(req, res) {
 *   const { device, i18n, locale } = req;
 *   const _locale = locale || i18n.locale;
 *
 *   const MyPage = (props) => (
 *     <AndesProvider locale={_locale} device={device}>
 *       <View {...props} />
 *     </AndesProvider>
 *   );
 *
 *   res.render(Demo, { device, locale: _locale });
 * };
 *
 * ...
 *
 * // app/pages/my-page/view.js
 * import React from 'react';
 * import Page from 'nordic/page';
 *
 * class View extends React.Component {
 *   render() {
 *     const { locale, device } = this.props;
 *
 *     return(
 *       <Page
 *         name="myPage"
 *         className="my-page"
 *         state={{ locale, device }}
 *       >
 *         Your page content
 *       </Page>
 *     )
 *   }
 * }
 *
 * export default View;
 *
 * ...
 *
 * // app/client/my-page.js
 * import React from 'react';
 * import { AndesProvider } from '@andes/context';
 * import { hydrate } from 'nordic/hydrate';
 * import MyPage from '../pages/my-page/view';
 *
 * const initialState = window.__PRELOADED_STATE__;
 *
 * hydrate(
 *   <AndesProvider locale={initialState.locale} device={initialState.device}>
 *     <MyPage {...initialState} />
 *   </AndesProvider>,
 *   document.getElementById('root-app'),
 * );
 */
export const AndesProvider: FunctionComponent<AndesProviderSpecificProps>;

type ContextValue = {
  csrfToken?: string;
  device?: Device;
  i18n: I18n;
  locale?: Locale;
};

type Translation = Record<string, Record<string, Array<string | null>>>;

type GetPatchedI18n = (
  context: ContextValue,
  moduleName: string,
  availableTranslations: Translation,
) => I18n;

export const getPatchedI18n: GetPatchedI18n;

type InjectTranslations = (
  i18n: I18n,
  locale: Locale,
  moduleName: string,
  availableTranslations: Translation,
) => void;

export const injectTranslations: InjectTranslations;

type UseId = (id?: string) => string;

export const useId: UseId;

type AndesContext = Context<ContextValue>;

export const AndesContext: AndesContext;

type UseCallAndesContext = (
  moduleName: string,
  andesTranslations?: Translation,
) => ContextValue | undefined;

type UseAndesContext = (
  moduleName?: string,
  andesTranslations?: Translation,
) => ContextValue;

export const useAndesContext: UseAndesContext;

// These guys are brought from @meli/i18n, it is not an exported type.
type PrimitiveTypes = boolean | number | string;

type I18nValues = Record<
  string,
  boolean | number | string | ((chunks: string) => string)
>;

type CreateI18nPgettext = (
  context: string,
  text: string,
  ...replacements:
    | Array<PrimitiveTypes>
    | [Array<PrimitiveTypes>]
    | [I18nValues]
) => string;

type CreateI18nNPgettext = (
  context: string,
  singularText: string,
  pluralText: string,
  quantity: number,
  ...replacements:
    | Array<PrimitiveTypes>
    | [Array<PrimitiveTypes>]
    | [I18nValues]
) => string;
